;
;   go run retroreverse.com/tools/cmd/codetracex86 \
;       -skip 0x3200 -base 0 -entry EC50 \
;       -o "Ultima Underworld (PC)/disasm/uw.raw.asm" \
;       "Ultima Underworld (PC)/game/UW.EXE"
